&lt;h3 id=&#34;编写语法-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编写语法-3&#34;&gt;#&lt;/a&gt; 编写语法&lt;/h3&gt;
&lt;figure class=&#34;highlight markdown&#34;&gt;&lt;figcaption data-lang=&#34;markdown&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token list punctuation&#34;&gt;1.&lt;/span&gt; 第一项&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token list punctuation&#34;&gt;2.&lt;/span&gt; 第二项&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token list punctuation&#34;&gt;-&lt;/span&gt; 嵌套无序&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token list punctuation&#34;&gt;3.&lt;/span&gt; 第三项&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token list punctuation&#34;&gt;-&lt;/span&gt; 无序 A&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token list punctuation&#34;&gt;-&lt;/span&gt; 无序 B&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token list punctuation&#34;&gt;-&lt;/span&gt; [ ] 未完成&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token list punctuation&#34;&gt;-&lt;/span&gt; [x] 已完成&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&amp;#123;.primary&amp;#125;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;（任务列表与  &lt;code&gt;&amp;#123;.primary&amp;#125;&lt;/code&gt;  之间需&lt;strong&gt;空一行&lt;/strong&gt;。）&lt;/p&gt;
&lt;hr /&gt;
&lt;h2 id=&#34;四-引用与分割线&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#四-引用与分割线&#34;&gt;#&lt;/a&gt; 四、引用与分割线&lt;/h2&gt;
&lt;h3 id=&#34;效果-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#效果-4&#34;&gt;#&lt;/a&gt; 效果&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;普通引用一段文字。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;blockquote&gt;&lt;p&gt;书摘或名言。&lt;/p&gt;
&lt;footer&gt;&lt;strong&gt;作者名&lt;/strong&gt;&lt;cite&gt;《书名》&lt;/cite&gt;&lt;/footer&gt;&lt;/blockquote&gt;&lt;/p&gt;
&lt;h3 id=&#34;编写语法-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编写语法-4&#34;&gt;#&lt;/a&gt; 编写语法&lt;/h3&gt;
&lt;figure class=&#34;highlight markdown&#34;&gt;&lt;figcaption data-lang=&#34;markdown&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token blockquote punctuation&#34;&gt;&gt;&lt;/span&gt; 引用内容&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;figure class=&#34;highlight liquid&#34;&gt;&lt;figcaption data-lang=&#34;liquid&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;&lt;blockquote&gt;&lt;p&gt;书摘内容&lt;/p&gt;
&lt;footer&gt;&lt;strong&gt;作者名&lt;/strong&gt;&lt;cite&gt;《书名》&lt;/cite&gt;&lt;/footer&gt;&lt;/blockquote&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;水平分割线：单独一行的  &lt;code&gt;---&lt;/code&gt; （上下空行更清晰）。&lt;/p&gt;
&lt;hr /&gt;
